/**
 * CatClock — a faithful HTML5 canvas port of the classic xclock cat mode.
 *
 * Original C source: xclock.c (MIT 1985, ported to X11/Motif by Philip J. Schneider, 1990).
 * The cat body, tail base, and eye outlines are the original XBM bitmaps,
 * embedded here as base64 and decoded at module load time.
 */

// ── Default colors (from xclock.ad) ───────────────────────────────────

const BG_COLOR = "#0000ff";          // background: blue
const CAT_COLOR = "#000000";         // cat body: black
const DETAIL_COLOR = "#ffffff";      // detail (eyes/belly/face): white
const TIE_COLOR = "#ff0000";         // bow tie: red
const HAND_COLOR = "#ff0000";        // clock hands fill: red
const HIGHLIGHT_COLOR = "#000000";   // hand outline: black

// ── Geometry constants (from xclock.c) ────────────────────────────────

const CAT_W = 150;                   // DEF_CAT_WIDTH
const CAT_H = 300;                   // DEF_CAT_HEIGHT
const CAT_BOTTOM = 210;              // DEF_CAT_BOTTOM
const TAIL_W = 150;                  // tail bitmap width
const TAIL_H = 89;                   // TAIL_HEIGHT
const EYES_W = 54;
const EYES_H = 23;
const EYES_X = 49;                   // X offset of eye region
const EYES_Y = 30;                   // Y offset of eye region

const N_TAILS = 16;                  // DEF_N_TAILS
const PADDING = 8;                   // DEF_ANALOG_PADDING

// ── Hand fractions (percent of radius) ────────────────────────────────

const MINUTE_HAND_FRACT = 70;
const HOUR_HAND_FRACT = 40;
const HAND_WIDTH_FRACT = 7;

// Replicate C integer math precisely:
//   radius = round((min(W,H) - 2*padding) / 3.45)
//   secondHandLength etc. = (FRACT * radius) / 100   (integer division)
//   handWidth = ((HAND_WIDTH_FRACT * radius) / 100) * 2
const RADIUS = Math.round((Math.min(CAT_W, CAT_H) - 2 * PADDING) / 3.45);
const MINUTE_HAND_LENGTH = (MINUTE_HAND_FRACT * RADIUS) / 100 | 0;
const HOUR_HAND_LENGTH = (HOUR_HAND_FRACT * RADIUS) / 100 | 0;
const HAND_WIDTH = (((HAND_WIDTH_FRACT * RADIUS) / 100) | 0) * 2;
const CENTER_X = CAT_W / 2;
const CENTER_Y = CAT_H / 2;

// ── Tail pendulum geometry (from CreateTailPixmap) ────────────────────

const TAIL_OFFSET = { x: 74, y: -15 };
const TAIL_PTS = [
  { x: 0, y: 0 },
  { x: 0, y: 76 },
  { x: 3, y: 82 },
  { x: 10, y: 84 },
  { x: 18, y: 82 },
  { x: 21, y: 76 },
  { x: 21, y: 70 },
];
const TAIL_OFF_CENTER_ANGLE = -0.08;
const TAIL_A = 0.4;
const TAIL_OMEGA = 1.0;
const TAIL_PHI = 3 * Math.PI / 2;

// ── Eye pendulum geometry (from CreateEyePixmap) ──────────────────────

const EYE_A = 0.7;
const EYE_OMEGA = 1.0;
const EYE_PHI = 3 * Math.PI / 2;

// ── XBM bitmap data (base64-encoded, LSB-first per byte) ──────────────
// (Original xbm files in this folder: catback.xbm catwhite.xbm cattie.xbm tail.xbm eyes.xbm)
const CATBACK_B64 = "";
const CATWHITE_B64 = "";
const CATTIE_B64 = "";
const TAIL_B64 = "";
const EYES_B64 = "/4D//3/APx8A/P8PAD4PAPj/BwA8BwDw/wMAOAMA4P8BADABAMD/AAAgAQDA/wAAIAEAwP8AACAAAIB/AAAAAACAfwAAAAAAgH8AAAAAAIB/AAAAAACAfwAAAAAAgH8AAAAAAIB/AAAAAQDA/wAAIAEAwP8AACABAMD/AAAgAwDg/wEAMAcA8P8DADgPAPj/BwA8HwD86g8APv+Af9V/wD8=";

function decodeB64(b64) {
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}

function parseHex(c) {
  const v = parseInt(c.slice(1), 16);
  return [(v >> 16) & 0xff, (v >> 8) & 0xff, v & 0xff];
}

// Render a 1-bit XBM bitmap to an offscreen canvas, painting bit=1 pixels in
// the given color and leaving bit=0 pixels transparent. Caller can drawImage
// this onto another canvas to layer it.
function makeXbmAlphaCanvas(bytes, w, h, color) {
  const cnv = document.createElement("canvas");
  cnv.width = w;
  cnv.height = h;
  const ctx = cnv.getContext("2d");
  const imgData = ctx.createImageData(w, h);
  const data = imgData.data;
  const bytesPerRow = Math.ceil(w / 8);
  const [r, g, b] = parseHex(color);
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const byte = bytes[y * bytesPerRow + (x >> 3)];
      const bit = (byte >> (x & 7)) & 1;
      if (bit) {
        const i = (y * w + x) * 4;
        data[i] = r;
        data[i + 1] = g;
        data[i + 2] = b;
        data[i + 3] = 255;
      }
    }
  }
  ctx.putImageData(imgData, 0, 0);
  return cnv;
}


// ── Decode bitmaps once at module load ────────────────────────────────

const CATBACK_BYTES = decodeB64(CATBACK_B64);
const CATWHITE_BYTES = decodeB64(CATWHITE_B64);
const CATTIE_BYTES = decodeB64(CATTIE_B64);
const TAIL_BYTES = decodeB64(TAIL_B64);
const EYES_BYTES = decodeB64(EYES_B64);

// Pre-rendered alpha canvases for layering.
let staticCatCanvas = null;
let tailBitsCanvas = null;
let eyesBitsCanvas = null;
let tailFrames = null;
let eyeFrames = null;

function buildStaticAssets() {
  if (staticCatCanvas) return;

  // Build the cat body: bg fill, then catback (catColor), catwhite (detail),
  // cattie (tieColor) layered on top via alpha-canvas drawImage.
  const catBack = makeXbmAlphaCanvas(CATBACK_BYTES, CAT_W, CAT_H, CAT_COLOR);
  const catWhite = makeXbmAlphaCanvas(CATWHITE_BYTES, CAT_W, CAT_H, DETAIL_COLOR);
  const catTie = makeXbmAlphaCanvas(CATTIE_BYTES, CAT_W, CAT_H, TIE_COLOR);

  staticCatCanvas = document.createElement("canvas");
  staticCatCanvas.width = CAT_W;
  staticCatCanvas.height = CAT_H;
  const sctx = staticCatCanvas.getContext("2d");
  sctx.fillStyle = BG_COLOR;
  sctx.fillRect(0, 0, CAT_W, CAT_H);
  sctx.drawImage(catBack, 0, 0);
  sctx.drawImage(catWhite, 0, 0);
  sctx.drawImage(catTie, 0, 0);

  // Cache the static tail/eye outline bitmaps in catColor — they get
  // composited beneath the swung tail line and pupil polygons each frame.
  tailBitsCanvas = makeXbmAlphaCanvas(TAIL_BYTES, TAIL_W, TAIL_H, CAT_COLOR);
  eyesBitsCanvas = makeXbmAlphaCanvas(EYES_BYTES, EYES_W, EYES_H, CAT_COLOR);

  // Pre-render N+1 tail frames and N+1 eye frames (indices 0..N_TAILS).
  tailFrames = new Array(N_TAILS + 1);
  eyeFrames = new Array(N_TAILS + 1);
  for (let i = 0; i <= N_TAILS; i++) {
    const t = (i * Math.PI) / N_TAILS;
    tailFrames[i] = makeTailFrame(t);
    eyeFrames[i] = makeEyeFrame(t);
  }
}


// ── Tail frame: bg + tail outline + swung tail line ───────────────────
//
// Replicates CreateTailPixmap: rotate the canonical tail polyline by
// `angle = A * sin(omega*t + phi)`, after first applying a -0.08 rad
// "off-center" rotation so the resting tail hangs slightly to the left.

function makeTailFrame(t) {
  const cnv = document.createElement("canvas");
  cnv.width = TAIL_W;
  cnv.height = TAIL_H;
  const ctx = cnv.getContext("2d");

  // Background fill, then static tail outline in catColor.
  ctx.fillStyle = BG_COLOR;
  ctx.fillRect(0, 0, TAIL_W, TAIL_H);
  ctx.drawImage(tailBitsCanvas, 0, 0);

  // Off-center rotation (matches C exactly: int truncation included).
  const so = Math.sin(TAIL_OFF_CENTER_ANGLE);
  const co = Math.cos(TAIL_OFF_CENTER_ANGLE);
  const offCenter = TAIL_PTS.map((p) => ({
    x: (p.x * co + p.y * so) | 0,
    y: (-p.x * so + p.y * co) | 0,
  }));

  // Pendulum rotation for time t.
  const angle = TAIL_A * Math.sin(TAIL_OMEGA * t + TAIL_PHI);
  const sa = Math.sin(angle);
  const ca = Math.cos(angle);
  const newTail = offCenter.map((p) => ({
    x: ((p.x * ca + p.y * sa) | 0) + TAIL_OFFSET.x,
    y: ((-p.x * sa + p.y * ca) | 0) + TAIL_OFFSET.y,
  }));

  // Stroke as a thick polyline with round caps/joins (matches X11 GC).
  ctx.strokeStyle = CAT_COLOR;
  ctx.lineWidth = 15;
  ctx.lineCap = "round";
  ctx.lineJoin = "round";
  ctx.beginPath();
  ctx.moveTo(newTail[0].x, newTail[0].y);
  for (let i = 1; i < newTail.length; i++) {
    ctx.lineTo(newTail[i].x, newTail[i].y);
  }
  ctx.stroke();

  return cnv;
}


// ── Eye frame: detail bg + eye outline + two pupil polygons ───────────
//
// Replicates CreateEyePixmap: trace points around the front of a sphere
// at z=2, projecting to 2D, with pendulum-driven gaze direction. Two
// arcs (forward in u, then back in u with a slightly different gaze
// offset) form one closed pupil polygon; the right eye is offset by 31px.

function makeEyeFrame(t) {
  const cnv = document.createElement("canvas");
  cnv.width = EYES_W;
  cnv.height = EYES_H;
  const ctx = cnv.getContext("2d");

  ctx.fillStyle = DETAIL_COLOR;
  ctx.fillRect(0, 0, EYES_W, EYES_H);
  ctx.drawImage(eyesBitsCanvas, 0, 0);

  const w = Math.PI / 2;
  const angle = EYE_A * Math.sin(EYE_OMEGA * t + EYE_PHI) + w;
  const x0 = 0, y0 = 0, z0 = 2, r = 1;

  const pts = [];
  // Forward sweep
  for (let u = -Math.PI / 2; u < Math.PI / 2; u += 0.25) {
    const px = x0 + r * Math.cos(u) * Math.cos(angle + Math.PI / 7);
    const pz = z0 + r * Math.cos(u) * Math.sin(angle + Math.PI / 7);
    const py = y0 + r * Math.sin(u);
    pts.push({
      x: ((pz === 0 ? px : px / pz) * 23 + 12) | 0,
      y: ((pz === 0 ? py : py / pz) * 23 + 11) | 0,
    });
  }
  // Reverse sweep (slightly different gaze offset closes the polygon)
  for (let u = Math.PI / 2; u > -Math.PI / 2; u -= 0.25) {
    const px = x0 + r * Math.cos(u) * Math.cos(angle - Math.PI / 7);
    const pz = z0 + r * Math.cos(u) * Math.sin(angle - Math.PI / 7);
    const py = y0 + r * Math.sin(u);
    pts.push({
      x: ((pz === 0 ? px : px / pz) * 23 + 12) | 0,
      y: ((pz === 0 ? py : py / pz) * 23 + 11) | 0,
    });
  }

  ctx.fillStyle = CAT_COLOR;
  // Left pupil
  ctx.beginPath();
  ctx.moveTo(pts[0].x, pts[0].y);
  for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
  ctx.closePath();
  ctx.fill();
  // Right pupil (offset by 31, per C source)
  ctx.beginPath();
  ctx.moveTo(pts[0].x + 31, pts[0].y);
  for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x + 31, pts[i].y);
  ctx.closePath();
  ctx.fill();

  return cnv;
}


// ── Clock hand: filled triangle with outlined border ──────────────────
//
// Replicates DrawHand: tip at (cx + L*sin, cy - L*cos); base-left and
// base-right offset perpendicular by handWidth. Filled in HAND_COLOR,
// outlined in HIGHLIGHT_COLOR.

function drawHand(ctx, length, width, fractionOfACircle) {
  const angle = 2 * Math.PI * fractionOfACircle;
  const ca = Math.cos(angle);
  const sa = Math.sin(angle);
  const wc = width * ca;
  const ws = width * sa;

  const x = CENTER_X + Math.round(length * sa);
  const y = CENTER_Y - Math.round(length * ca);
  const x1 = CENTER_X - Math.round(ws + wc);
  const y1 = CENTER_Y + Math.round(wc - ws);
  const x2 = CENTER_X - Math.round(ws - wc);
  const y2 = CENTER_Y + Math.round(wc + ws);

  ctx.beginPath();
  ctx.moveTo(x, y);
  ctx.lineTo(x1, y1);
  ctx.lineTo(x2, y2);
  ctx.closePath();
  ctx.fillStyle = HAND_COLOR;
  ctx.fill();
  ctx.lineWidth = 1;
  ctx.strokeStyle = HIGHLIGHT_COLOR;
  ctx.stroke();
}

// ── Tool render function ──────────────────────────────────────────────

const STYLES = `
@layer package {
  :root,
  :host,
  [theme] {
    --catclock-bg: var(--studio-fill, white);
  }
}

.catclock-root {
  width: 100%;
  height: 100%;
  background: var(--catclock-bg);
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

.catclock-canvas {
  max-width: 100%;
  max-height: 100%;
  aspect-ratio: ${CAT_W} / ${CAT_H};
  image-rendering: pixelated;
  image-rendering: -moz-crisp-edges;
  image-rendering: crisp-edges;
}
`;

export function Tool(handle, element) {
  buildStaticAssets();

  const style = document.createElement("style");
  style.textContent = STYLES;
  element.appendChild(style);

  const root = document.createElement("div");
  root.className = "catclock-root";
  element.appendChild(root);

  const canvas = document.createElement("canvas");
  canvas.className = "catclock-canvas";
  canvas.width = CAT_W;
  canvas.height = CAT_H;
  root.appendChild(canvas);
  const ctx = canvas.getContext("2d");

  // Animation state mirrors xclock.c's UpdateEyesAndTail static locals.
  let curTail = 0;
  let tailDir = 1;
  let destroyed = false;

  function tick() {
    if (destroyed) return;

    // 1. Static cat body (catback + catwhite + cattie composite)
    ctx.drawImage(staticCatCanvas, 0, 0);

    // 2. Clock hands. Cat mode is 12-hour with no second hand.
    const now = new Date();
    let hour = now.getHours() % 12;
    const minute = now.getMinutes();
    drawHand(ctx, MINUTE_HAND_LENGTH, HAND_WIDTH, minute / 60.0);
    drawHand(
      ctx,
      HOUR_HAND_LENGTH,
      HAND_WIDTH,
      (hour + minute / 60.0) / 12.0,
    );

    // 3. Tail (replaces full bottom strip — see XCopyPlane in C source)
    ctx.drawImage(tailFrames[curTail], 0, CAT_BOTTOM + 1);

    // 4. Eyes (replaces eye region — pupils animate with tail phase)
    ctx.drawImage(eyeFrames[curTail], EYES_X, EYES_Y);

    // Step the pendulum index back-and-forth between 0 and N_TAILS.
    if (curTail === 0 && tailDir === -1) {
      curTail = 1;
      tailDir = 1;
    } else if (curTail === N_TAILS && tailDir === 1) {
      curTail = N_TAILS - 1;
      tailDir = -1;
    } else {
      curTail += tailDir;
    }
  }

  tick();
  // 1000/N_TAILS ms per frame — same cadence as the C source's update timer.
  const timer = setInterval(tick, Math.round(1000 / N_TAILS));

  return () => {
    destroyed = true;
    clearInterval(timer);
    style.remove();
    root.remove();
  };
}

// ── Datatype ──────────────────────────────────────────────────────────

export const CatclockDatatype = {
  init(doc) {
    doc.title = "Cat Clock";
  },
  getTitle(doc) {
    return doc.title || "Cat Clock";
  },
  setTitle(doc, title) {
    doc.title = title;
  },
  markCopy(doc) {
    doc.title = "Copy of " + (doc.title || "Cat Clock");
  },
};

// ── Plugin exports ────────────────────────────────────────────────────

export const plugins = [
  {
    type: "patchwork:datatype",
    id: "catclock",
    name: "Cat Clock",
    icon: "Cat",
    async load() {
      return CatclockDatatype;
    },
  },
  {
    type: "patchwork:tool",
    id: "catclock",
    name: "Cat Clock",
    icon: "Cat",
    supportedDatatypes: ["catclock"],
    async load() {
      return Tool;
    },
  },
];
